var richText = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Discover PENpal, a clever device that brings books, posters, and stickers to life by playing audio when touched, creating a fun, multisensory reading experience for children. Compatible with over 1700 dual-language titles in English or more than 60 other languages, it detects tiny, invisible barcodes on pages to deliver stories, sounds, and narration instantly. With free software like CreateLINK for sound-enabling any book, FREElink for downloading audio files, and ShareLINK for collaborative group activities, PENpal is portable, easy to use, and expandable up to 32GB\u2014plus, it doubles as a microphone to record and replay voices on unique barcode stickers without scrolling through files." }), /* @__PURE__ */ e("p", { children: "This versatile tool sparks imagination in classrooms and homes, supporting group discussions, language learning, and personal storytelling where kids can hear tales in familiar voices. Ideal for teachers fostering teamwork or families cherishing custom recordings, PENpal includes free instructional videos, software, and a starter course to get everyone exploring quickly, making it a joyful way to enhance reading, empathy, and cultural connections for young learners." })] });
var richText1 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "These vibrant, reusable stickers make audio recording a breeze for little learners, requiring no button presses on the PENpal\u2014just switch to record mode, tap the circle to start, the square to stop, and the arrow to play back, adding sound to books, posters, toys, or displays in any language. Designed for Early Years and Special Educational Needs (SEN), their bright colours and simple shapes are perfect for young children, encouraging independent use to label drawings, timelines, or interactive projects with voices and sounds that bring learning to life." }), /* @__PURE__ */ e("p", { children: "Ideal for inclusive classrooms or playful home activities, these stickers help kids build speaking confidence and storytelling skills by instantly hearing their own recordings, fostering creativity and progress tracking. Teachers and parents can create engaging, tailored resources that support vocabulary growth and sensory exploration, making every moment a fun, multi-lingual adventure for the youngest learners." })] });
var richText2 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Talking Stickers transform books, posters, flash cards, and more into lively audio experiences by linking recordings to special labels, compatible with the TalkingPEN\u2019s 4GB memory for hours of content in any of over 60 languages. Easily shared via USB, these stickers can be attached to mind maps, drawings, toys, oral histories, timelines, or displays, making them a versatile tool for labelling and storytelling, as celebrated by the RNIB for its best-selling PENfriend labelling feature. With two types\u2014overwritable student labels for repeated use across projects without duplication and protected teachers\u2019 labels for secure content\u2014these stickers suit diverse learning needs." }), /* @__PURE__ */ e("p", { children: "A finalist at BETT 2010, this innovative resource empowers teachers to create tailored, multi-lingual materials that spark engagement, while children build confidence in speaking and storytelling by instantly replaying their voices to track progress. Perfect for classrooms or home, Talking Stickers encourage creativity, collaboration, and cultural exploration, making every project a fun, inclusive adventure for young learners." })] });
var richText3 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: `Unlock easy conversations in school with this A3 laminated poster, paired with a PENpal device to hear key words and phrases spoken fluently in over 30 languages, including English, Albanian, Arabic, Bengali/Sylheti, Bulgarian, Cantonese, Czech, Farsi, French, German, Hungarian, Italian, Japanese, Kurdish, Latvian, Lithuanian, Malayalam, Mandarin, Nepali, Panjabi, Polish, Portuguese, Romanian, Russian, Slovakian, Somali, Spanish, Turkish, Urdu, Dari, Pashto, and Ukrainian. Simply touch the PENpal to select a language "button" and then tap the square next to a phrase\u2014like "Please bring your child at 9 o'clock"\u2014to hear it instantly in that tongue, switching between languages with a single touch. This practical package includes the durable chart, the PENpal, and all audio files, making it a breeze for teachers, office staff, or parents to communicate everyday needs without barriers.` }), /* @__PURE__ */ e("p", { children: "Tried and tested for common school scenarios, this resource is a must-have for settings with English as an Additional Language (EAL) children, supporting smooth inductions, daily routines, and family interactions in a fun, interactive way. Ideal for classrooms, receptions, or home use, it builds confidence in multilingual environments, fosters inclusion, and helps everyone feel connected through clear, respectful exchanges." })] });
var richText4 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Embark on an exciting storytelling journey with the Literacy Toolkit - Mountain Adventure, designed for children aged 6 to 11 to craft tales at different levels of complexity, from simple plots to detailed narratives. Using a PENpal device, young creators can tap to hear helpful instructions and key prompts, guiding them through building a mountain-themed story full of peaks, challenges, and triumphs. This lightweight, affordable tool turns imagination into structured adventures, making it easy for kids to climb from basic ideas to epic endings with giggles and wonder along the way." }), /* @__PURE__ */ e("p", { children: "Perfect for classrooms, homeschooling, or family bonding, this dual language-compatible toolkit boosts literacy skills, confidence in writing, and creative thinking while supporting EAL learners through audio in multiple languages. Teachers and parents will love how it encourages step-by-step progress, fostering a love of stories that grows with every use, all in a portable format ready for endless replay and inspiration." })] });
var richText5 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Shortlisted for the NASEN Award for ICT Inclusivity, the Key Terms Vocabulary Poster is a vibrant A3 resource that delivers over eight hours of detailed definitions, explanations, and examples of essential English National Curriculum terms for Key Stages 2 and 3, accessible with a PENpal device. Covering 40 terms like alliteration, metaphor, punctuation, and simile in 17 languages\u2014Arabic, Czech, English, Farsi, French, Lithuanian, Mandarin, Panjabi, Portuguese, Russian, Slovakian, Somali, Spanish, Sylheti, Turkish, Urdu, and Yoruba\u2014this poster helps students grasp key concepts quickly by tapping to hear clear, native-spoken explanations, making it ideal for both EAL learners and native English speakers." }), /* @__PURE__ */ e("p", { children: "Perfect for classrooms, this inclusive tool supports new arrivals by offering access to vital vocabulary in their home language while aiding teachers in assessing comprehension effortlessly. It fosters confidence, enriches understanding of literary concepts like imagery and narrative, and encourages cross-curricular learning with companion posters in Maths and Science, all compatible with a single PENpal, sparking curiosity and connection across diverse learners." })] });
var richText6 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Shortlisted for the NASEN Award for ICT Inclusivity, the Key Terms Maths Poster is an engaging A3 resource offering over eight hours of clear definitions, explanations, and examples of essential Maths National Curriculum terms for Key Stages 3 and 4, brought to life with a PENpal or RecorderPEN. Covering 40 vital terms such as addition, angle, circumference, fraction, percentage, symmetry, and volume in 18 languages\u2014including Arabic, Czech, English, Farsi, French, Lithuanian, Mandarin, Panjabi, Polish, Portuguese, Russian, Slovakian, Somali, Spanish, Sylheti, Turkish, Urdu, and Yoruba\u2014this poster enables students to tap and hear native-spoken explanations, supporting both EAL learners and native English speakers in grasping core concepts with ease." }), /* @__PURE__ */ e("p", { children: "Ideal for diverse classrooms, this interactive tool helps new arrivals access maths vocabulary in their home language while allowing teachers to quickly assess understanding by selecting a language and term. Paired with companion posters in Science and English, all compatible with a single PENpal, it fosters confidence, enhances mathematical fluency, and sparks curiosity, making it a perfect resource for inclusive learning and collaborative exploration." })] });
var richText7 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Shortlisted for the NASEN Award for ICT Inclusivity, the Key Terms Science Poster is a vibrant A3 resource delivering over eight hours of detailed definitions, explanations, and examples of essential Science National Curriculum terms for Key Stages 3 and 4 (ages 9-14), accessible via a PENpal or RecorderPEN. Featuring 36 key terms like absorb, acid, combustion, digestion, evaporation, organism, respiration, and vertebrate, it offers audio explanations in 19 languages\u2014Arabic, Czech, English, Farsi, French, Gujarati, Korean, Lithuanian, Mandarin, Panjabi, Polish, Portuguese, Russian, Slovakian, Somali, Sylheti (Bangla), Turkish, Urdu, and Vietnamese\u2014allowing students to tap and hear native-spoken content for quick understanding, perfect for both EAL learners and native English speakers." }), /* @__PURE__ */ e("p", { children: "This interactive poster is a classroom gem, enabling teachers to assess new arrivals\u2019 comprehension by selecting a language and term, while helping all students build scientific fluency in their home language or English. Compatible with a single PENpal alongside Maths and English posters, it sparks curiosity, supports inclusive learning, and encourages exploration of concepts like ecosystems and chemical reactions, making science accessible and exciting for everyone." })] });
var richText8 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Shortlisted for the NASEN Award for ICT Inclusivity, the Key Terms Geography Poster is a vibrant A3 resource delivering over eight hours of detailed definitions, explanations, and examples of 35 essential Geography National Curriculum terms for Key Stages 3 and 4, accessible with a PENpal. Covering terms like atlas, contour, erosion, latitude, longitude, pollution, and urban in 22 languages\u2014Arabic, Czech, English, Farsi, French, Gujarati, Japanese, Korean, Lithuanian, Mandarin, Panjabi, Polish, Portuguese, Russian, Slovakian, Somali, Spanish, Sylheti, Turkish, Urdu, Vietnamese, and Yoruba\u2014this poster allows students to tap and hear native-spoken explanations, supporting EAL learners and native English speakers in mastering geographic concepts effortlessly." }), /* @__PURE__ */ e("p", { children: "Perfect for diverse classrooms, this interactive tool helps teachers assess new arrivals\u2019 understanding by selecting a language and term, fostering inclusive learning and confidence in exploring topics like habitats, weather, and infrastructure. Compatible with a single PENpal alongside English, Maths, and Science posters, it ignites curiosity about the world, encourages cross-curricular connections, and makes geography engaging and accessible for all young explorers." })] });
var richText9 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: 'Brighten any classroom with the Say Thank You A2 laminated poster, a vibrant resource that teaches children how to express gratitude in over 30 languages, including Arabic, Cantonese, Czech, English, Farsi, French, German, Greek, Gujarati, Hindi, Kurdish, Latvian, Malayalam, Panjabi, Polish, Portuguese, Romanian, Romany, Slovakian, Slovenian, Somali, Spanish, Swedish, Sylheti, Turkish, Twi, Urdu, Vietnamese, Welsh, Yoruba, and more, using a PENpal to hear native pronunciations. By tapping each language\u2019s word for "thank you," kids can listen and repeat, learning simple phrases while celebrating global cultures in a fun, interactive way.' }), /* @__PURE__ */ e("p", { children: "This engaging poster is a must-have for schools, fostering inclusivity and respect through shared expressions of kindness. Ideal for EAL learners and native speakers alike, it encourages conversations about diversity, builds language confidence, and creates a welcoming environment where every child can feel valued and connected through the universal act of saying thanks." })] });
var richText10 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: 'Greet parents and children in their home languages with this vibrant, laminated A2 poster, featuring a heartfelt "Welcome" in 50 languages, including Albanian, Arabic, Bengali, Bulgarian, Chinese, Croatian, Czech, Dutch, English, Farsi, French, German, Greek, Gujarati, Hebrew, Hindi, Hungarian, Irish, Italian, Japanese, Korean, Kurdish (Kurmanji and Sorani), Latvian, Lithuanian, Malayalam, Nepali, Norwegian, Panjabi, Polish, Portuguese, Romani, Romanian, Romany, Russian, Scottish Gaelic, Slovak, Somali, Spanish, Swahili, Swedish, Tagalog, Tamil, Turkish, Twi, Urdu, Vietnamese, Welsh, Yiddish, and Yoruba. Displayed in school receptions or classrooms, this durable, easy-to-clean poster invites pupils to pick a language, sparking discussions about cultures, geography, and global connections for a fun, interactive learning experience.' }), /* @__PURE__ */ e("p", { children: "While not audio-enabled, you can bring it to life with TalkingPENs and recordable labels, letting pupils and families record their own greetings to share. Perfect for fostering inclusivity and celebrating diversity, this popular resource creates a warm, welcoming atmosphere, encouraging children to explore new languages and feel valued in a multicultural school community." })] });
var richText11 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: 'Brighten any space with the Say Hello Poster, a beautifully illustrated A2 laminated resource by Irene Wise that welcomes new arrivals and international visitors with the word "hello" in 36 languages, including Italian, Portuguese, Arabic, Luganda, Korean, French, Greek, Ukrainian, Albanian, Czech/Slovakian, Romany, Gujarati, Hindi, Urdu, Vietnamese, Somali, Panjabi, Swahili, Croatian, Finnish, Turkish, Romanian, Lithuanian, German, Chinese, Gaelic, Swedish, Norwegian, Spanish, Bengali, Polish, Russian, Welsh, Tagalog, Japanese, and Farsi. This vibrant, durable poster, while not audio-enabled, can be brought to life with TalkingPENs and recordable labels for pupils or families to add their own greetings, making it a lively tool for celebrating global connections.' }), /* @__PURE__ */ e("p", { children: "Perfect for school receptions, classrooms, or community spaces, this poster fosters inclusivity and sparks conversations about cultures and languages, encouraging children to explore diversity through a simple, universal greeting. It\u2019s an ideal resource for creating a welcoming atmosphere, supporting EAL learners, and inspiring young ones to share their heritage with pride and joy." })] });
var richText12 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "The Talking Phonics 2 pack, designed for ages 5-8, builds on Pack 1 by helping children connect what they see with what they hear through hands-on, PENpal-compatible activities. With 10 charts, 50 picture and grapheme/digraph flashcards, 6 silly question cards, 62 tricky word tiles, and a guidance booklet, kids can tap to hear phonemes, digraphs, and tricky words, record their own attempts, and compare them for instant feedback. These engaging tools encourage practical investigation, letting young learners revisit games independently to boost confidence during child-led play." }), /* @__PURE__ */ e("p", { children: "Perfect for classrooms or home learning, this vibrant pack supports EAL students and emerging readers by offering audio in multiple languages, fostering phonics mastery through repetition and fun. Teachers and parents will love how it promotes independent exploration, builds speaking and listening skills, and sparks a love for words, making literacy a joyful adventure for every child." })] });
var richText13 = /* @__PURE__ */ a(i.Fragment, { children: [/* @__PURE__ */ e("p", { children: "The Touch, Listen and Learn Flip Charts book offers an exciting way for young children to explore essential words and themes through 11 interactive, PENpal-compatible charts covering Home, Fruit and Vegetables, Animals, Transport, In the Classroom, Colours, Numbers, Parts of the Body, Shapes, Clothes, and Family. Kids tap to hear words and play audio games that build speaking, listening, and reading skills, following a scaffolded approach that layers new learning on familiar concepts, while teachers can record custom questions or comments to personalise each chart for tailored fun." }), /* @__PURE__ */ e("p", { children: "Perfect for Early Years and EAL learners, this vibrant flip chart set sparks curiosity and confidence in classrooms or at home, encouraging independent exploration through multisensory play. With its engaging audio and colourful visuals, it fosters vocabulary growth, cultural connection, and collaborative learning, making it an ideal tool for teachers and parents to inspire a love of words in young adventurers." })] });
